    /// Target Heat identity (Firemark)
    firemark: String,

    /// Output format mode
    #[arg(long, value_enum, default_value = "full")]
    format: ParadeFormatArg,

    /// Target Pace coronet (required for --format detail)
    #[arg(long)]
