        before: args.before,
        after: args.after,
        first: args.first,
        last: args.last,
    };

    match gallops.rail(rail_args) {
        Ok(new_order) => {
            if let Err(e) = gallops.save(&args.file) {
                eprintln!("jjx_rail: error saving Gallops: {}", e);
