            match lock.vvcc_commit(&commit_args) {
                Ok(hash) => eprintln!("jjx_rail: committed {}", &hash[..8]),
                Err(e) => eprintln!("jjx_rail: commit warning: {}", e),
            }

            for coronet in new_order {
                println!("{}", coronet);
            }
            0
        }
        Err(e) => {
            eprintln!("jjx_rail: error: {}", e);
