    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
    file: PathBuf,

    /// Target Pace identity (Coronet)
    coronet: String,

    /// Target state (rough, primed, complete, abandoned)
    #[arg(long)]
    state: Option<String>,

    /// Execution guidance (required if state is primed)
    #[arg(long, short = 'd')]
