fn run_rail(args: RailArgs) -> i32 {
    use crate::jjrg_gallops::RailArgs as LibRailArgs;

    // Acquire lock FIRST - fail fast if another operation is in progress
    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
